const GenerateSvgPhotoStandars  = ({ pageSize, photoType, urlImag, customGap }) => {

	const [obs, set_obs] = useState(1);
	//const [svgData, setSvgData] = useState(null);
	let idKey = `${pageSize?.[0]}X${pageSize?.[1]}`;
	


	const updObs =  (v) => {
		set_obs(gen16CodeId());
	}


	const calculateSvgFrame =  (p, url, phT) => {
		var i = new Image();
		let gap =  customGap || 8;
		i.onload = function(){

	
			
		
			
			let inchW = i.width / phT[0];
			let pgW = inchW * p[0];

			let inchH = i.height / phT[1];
			let pgH = inchH * p[1];

		


			let num_img_w = Math.floor(pgW / (i.width ));
			let num_img_h = Math.floor(pgH /  (i.height ));

			let marginW = pgW - (num_img_w * i.width);
			let marginH = pgH - (num_img_h * i.height);

		

			let gapWI =  (marginW	 - (num_img_w - 1) *gap) /2 ;

			let gapH =  marginH / (num_img_h + 1);





			let takefrompictureW =  marginW >0 ? 0 : gap / 2;
			let takefrompictureH =  marginH >0 ? 0 : gap / 2;

			
			let imagesPosition = [];
			for(let h = 0; h< num_img_h; h ++  ){
				for(let w = 0; w< num_img_w; w ++  ){

					let ghp = w === 0 ?gapWI : gapWI + w*gap;
					let obj = {
						x: (w *i.width) + ghp,
						y: (h *i.height) + gapH*(h+1),
						w:i.width - takefrompictureW,
						h:i.height- takefrompictureH
					};
		
					imagesPosition.push(obj);
				}
			}

			let dmz = { pgW , pgH}

			updStore("svgData_"+idKey,{
				dmz,
				imagesPosition
			});

			updObs();
			//setSvgData()


		};

		i.src = url; 
		
	}



	useEffect(() => {
		
		calculateSvgFrame(pageSize,  urlImag, photoType);

	}, [pageSize, photoType,  urlImag ]);
	

	let svgData = getStore("svgData_"+idKey);

	if(!svgData?.dmz?.pgH){
		return null;
	}
	// console.log(idKey)
	// console.log(JSON.stringify(svgData))
	
	return (

		
		<svg id={idKey} xmlns="http://www.w3.org/2000/svg" width="100%" height="100%" viewBox={`0 0 ${svgData?.dmz?.pgW} ${svgData.dmz.pgH}`} preserveAspectRatio="xMidYMid meet">
			<style type="text/css">
							{`@font-face {
								font-family: "Google Sans";
								src: url(http://fonts.gstatic.com/s/googlesans/v14/4UabrENHsxJlGDuGo1OIlLU94YtzCwY.woff2)

							}`}
			</style>
			<rect width={svgData.dmz.pgW} height={svgData.dmz.pgH} fill="#ffffff"></rect>
			{svgData.imagesPosition.map((im,indImg)=> <SvgPhotoItem key={indImg+"_svg"+idKey } idKey={idKey} im={im} urlImag={urlImag} /> )}
			
		</svg>

	)

}





